## Testing your implementation

These examples demonstrate how to test your implementation when using Tooltip within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the tooltip renders and displays content on interaction

```tsx
import { describe, it, expect } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Tooltip, Button, NimbusProvider } from "@commercetools/nimbus";

describe("Tooltip - Basic rendering", () => {
  it("renders trigger element", () => {
    render(
      <NimbusProvider>
        <Tooltip.Root>
          <Button>Hover me</Button>
          <Tooltip.Content>Tooltip text</Tooltip.Content>
        </Tooltip.Root>
      </NimbusProvider>
    );

    expect(
      screen.getByRole("button", { name: /hover me/i })
    ).toBeInTheDocument();
  });

  it("shows tooltip content on focus", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Tooltip.Root>
          <Button>Hover me</Button>
          <Tooltip.Content>Tooltip text</Tooltip.Content>
        </Tooltip.Root>
      </NimbusProvider>
    );

    // Focus the button using tab
    await user.tab();

    await waitFor(() => {
      expect(screen.getByRole("tooltip")).toBeInTheDocument();
      expect(screen.getByText("Tooltip text")).toBeInTheDocument();
    });
  });
});
```

### Interaction Tests

Test focus interactions (hover tests require browser environment)

```tsx
import { describe, it, expect } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Tooltip, Button, NimbusProvider } from "@commercetools/nimbus";

describe("Tooltip - Interactions", () => {
  it("shows tooltip on focus", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Tooltip.Root>
          <Button>Action Button</Button>
          <Tooltip.Content>Action tooltip</Tooltip.Content>
        </Tooltip.Root>
      </NimbusProvider>
    );

    // Use userEvent.tab() instead of element.focus() to avoid act() warnings
    await user.tab();

    await waitFor(() => {
      expect(screen.getByRole("tooltip")).toBeInTheDocument();
      expect(screen.getByText("Action tooltip")).toBeInTheDocument();
    });
  });

  it("hides tooltip when focus leaves", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <Tooltip.Root>
          <Button>First</Button>
          <Tooltip.Content>First tooltip</Tooltip.Content>
        </Tooltip.Root>
        <Button>Second</Button>
      </NimbusProvider>
    );

    // Focus first button
    await user.tab();
    await waitFor(() => {
      expect(screen.getByRole("tooltip")).toBeInTheDocument();
    });

    // Focus second button
    await user.tab();
    await waitFor(() => {
      expect(screen.queryByRole("tooltip")).not.toBeInTheDocument();
    });
  });
});
```

### Testing Placement

Verify tooltip positioning

```tsx
import { describe, it, expect } from "vitest";
